import{_ as s,c as n,o as a,a as l}from"./app.aaf606c4.js";const h='{"title":"Enums","description":"","frontmatter":{},"headers":[{"level":2,"title":"The Why","slug":"the-why"},{"level":2,"title":"Package","slug":"package"},{"level":2,"title":"Defininition and Creation","slug":"defininition-and-creation"},{"level":2,"title":"Working with created enums","slug":"working-with-created-enums"},{"level":2,"title":"Conclusion","slug":"conclusion"}],"relativePath":"guide/enum.md"}',o={},e=l(`<h1 id="enums" tabindex="-1">Enums <a class="header-anchor" href="#enums" aria-hidden="true">#</a></h1><h2 id="the-why" tabindex="-1">The Why <a class="header-anchor" href="#the-why" aria-hidden="true">#</a></h2><p>SCALE spec comes from Rust programming language that has <a href="https://doc.rust-lang.org/book/ch06-01-defining-an-enum.html" target="_blank" rel="noopener noreferrer">Enums</a>, so any implementation of this codec has to work with this concept. Obviously, JavaScript doesn&#39;t have any native syntax/semantics to handle it. TypeScript&#39;s enums don&#39;t suit here neither because of the difference between them and Rust&#39;s ones (primarily because they don&#39;t have values associated with variants like in Rust). Thus, this library exists and tries to solve the problem of enums definition, creation and handling.</p><h2 id="package" tabindex="-1">Package <a class="header-anchor" href="#package" aria-hidden="true">#</a></h2><p>Available on NPM:</p><div class="language-bash"><pre class="shiki" style="background-color:#ffffff;"><code><span class="line"><span style="color:#24292F;">npm i @scale-codec/enum</span></span>
<span class="line"></span></code></pre></div><h2 id="defininition-and-creation" tabindex="-1">Defininition and Creation <a class="header-anchor" href="#defininition-and-creation" aria-hidden="true">#</a></h2><p><code>Enum</code> class from this package of course is not the same as enums in Rust. It&#39;s just a simple strongly-typed generic class with enum tag and associated content if it exists. Associations validation is up to TypeScript.</p><p>Let&#39;s take a look at the sample enum from Rust:</p><div class="language-rust"><pre class="shiki" style="background-color:#ffffff;"><code><span class="line"><span style="color:#CF222E;">enum</span><span style="color:#24292F;"> </span><span style="color:#953800;">Message</span><span style="color:#24292F;"> {</span></span>
<span class="line"><span style="color:#24292F;">    </span><span style="color:#953800;">Quit</span><span style="color:#24292F;">,</span></span>
<span class="line"><span style="color:#24292F;">    </span><span style="color:#8250DF;">Log</span><span style="color:#24292F;">(</span><span style="color:#953800;">String</span><span style="color:#24292F;">)</span></span>
<span class="line"><span style="color:#24292F;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CF222E;">let</span><span style="color:#24292F;"> msg </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> </span><span style="color:#953800;">Message</span><span style="color:#CF222E;">::</span><span style="color:#953800;">Quit</span><span style="color:#24292F;">;</span></span>
<span class="line"><span style="color:#CF222E;">let</span><span style="color:#24292F;"> msg </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> </span><span style="color:#953800;">Message</span><span style="color:#CF222E;">::</span><span style="color:#8250DF;">Log</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&quot;Rock&quot;</span><span style="color:#CF222E;">.</span><span style="color:#8250DF;">to_owned</span><span style="color:#24292F;">());</span></span>
<span class="line"></span></code></pre></div><p>It contains one empty variant - <code>Quit</code>, and one valuable (non-empty) variant - <code>Log(String)</code>.</p><p>With <code>@scale-codec/enum</code> you can define the same enum in this way:</p><div class="language-ts"><pre class="shiki" style="background-color:#ffffff;"><code><span class="line"><span style="color:#CF222E;">import</span><span style="color:#24292F;"> { Enum } </span><span style="color:#CF222E;">from</span><span style="color:#24292F;"> </span><span style="color:#0A3069;">&#39;@scale-codec/enum&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CF222E;">type</span><span style="color:#24292F;"> </span><span style="color:#953800;">Message</span><span style="color:#24292F;"> </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> </span><span style="color:#953800;">Enum</span><span style="color:#24292F;">&lt;</span><span style="color:#0A3069;">&#39;Quit&#39;</span><span style="color:#24292F;"> </span><span style="color:#CF222E;">|</span><span style="color:#24292F;"> [</span><span style="color:#0A3069;">&#39;Log&#39;</span><span style="color:#24292F;">, </span><span style="color:#0550AE;">string</span><span style="color:#24292F;">]&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CF222E;">let</span><span style="color:#24292F;"> msg</span><span style="color:#CF222E;">:</span><span style="color:#24292F;"> </span><span style="color:#953800;">Message</span><span style="color:#24292F;"> </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> Enum.</span><span style="color:#8250DF;">variant</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;Quit&#39;</span><span style="color:#24292F;">)</span></span>
<span class="line"><span style="color:#24292F;">msg </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> Enum.</span><span style="color:#8250DF;">variant</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;Log&#39;</span><span style="color:#24292F;">, </span><span style="color:#0A3069;">&#39;hello&#39;</span><span style="color:#24292F;">)</span></span>
<span class="line"></span></code></pre></div><p>Variants are defined with <code>string | [tag: string, value: any]</code> signature</p><p>Enum value could be <strong>created</strong> with <code>.variant()</code> factory:</p><div class="language-ts"><pre class="shiki" style="background-color:#ffffff;"><code><span class="line"><span style="color:#CF222E;">let</span><span style="color:#24292F;"> msg</span><span style="color:#CF222E;">:</span><span style="color:#24292F;"> </span><span style="color:#953800;">Message</span><span style="color:#24292F;"> </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> Enum.</span><span style="color:#8250DF;">variant</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;Quit&#39;</span><span style="color:#24292F;">)</span></span>
<span class="line"><span style="color:#24292F;">msg </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> Enum.</span><span style="color:#8250DF;">variant</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;Log&#39;</span><span style="color:#24292F;">, </span><span style="color:#0A3069;">&#39;hello&#39;</span><span style="color:#24292F;">)</span></span>
<span class="line"></span></code></pre></div><h2 id="working-with-created-enums" tabindex="-1">Working with created enums <a class="header-anchor" href="#working-with-created-enums" aria-hidden="true">#</a></h2><ul><li><p><code>.is(tag)</code> - to check for enum&#39;s actual tag, and <code>.as(tag)</code> - to extract enum value if its tag is appropriate, throw otherwise</p><div class="language-ts"><pre class="shiki" style="background-color:#ffffff;"><code><span class="line"><span style="color:#CF222E;">const</span><span style="color:#24292F;"> </span><span style="color:#0550AE;">result</span><span style="color:#CF222E;">:</span><span style="color:#24292F;"> </span><span style="color:#953800;">Result</span><span style="color:#24292F;">&lt;</span><span style="color:#0550AE;">number</span><span style="color:#24292F;">, </span><span style="color:#0550AE;">string</span><span style="color:#24292F;">&gt; </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> </span><span style="color:#6E7781;">/* --snip-- */</span><span style="color:#24292F;"> ___</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CF222E;">if</span><span style="color:#24292F;"> (result.</span><span style="color:#8250DF;">is</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;Ok&#39;</span><span style="color:#24292F;">)) {</span></span>
<span class="line"><span style="color:#24292F;">  </span><span style="color:#CF222E;">const</span><span style="color:#24292F;"> </span><span style="color:#0550AE;">num</span><span style="color:#24292F;"> </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> result.</span><span style="color:#8250DF;">as</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;Ok&#39;</span><span style="color:#24292F;">)</span></span>
<span class="line"><span style="color:#24292F;">  console.</span><span style="color:#8250DF;">log</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;Task result num:&#39;</span><span style="color:#24292F;">, num)</span></span>
<span class="line"><span style="color:#24292F;">} </span><span style="color:#CF222E;">else</span><span style="color:#24292F;"> {</span></span>
<span class="line"><span style="color:#24292F;">  </span><span style="color:#CF222E;">const</span><span style="color:#24292F;"> </span><span style="color:#0550AE;">errorMessage</span><span style="color:#24292F;"> </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> result.</span><span style="color:#8250DF;">as</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;Err&#39;</span><span style="color:#24292F;">)</span></span>
<span class="line"><span style="color:#24292F;">  console.</span><span style="color:#8250DF;">error</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;Task resulted with an error:&#39;</span><span style="color:#24292F;">, errorMessage)</span></span>
<span class="line"><span style="color:#24292F;">}</span></span>
<span class="line"></span></code></pre></div></li><li><p><code>.match(matchMap)</code> - to use a poor analogy of pattern matching</p><div class="language-ts"><pre class="shiki" style="background-color:#ffffff;"><code><span class="line"><span style="color:#CF222E;">const</span><span style="color:#24292F;"> </span><span style="color:#0550AE;">result</span><span style="color:#CF222E;">:</span><span style="color:#24292F;"> </span><span style="color:#953800;">Result</span><span style="color:#24292F;">&lt;</span><span style="color:#0550AE;">number</span><span style="color:#24292F;">, </span><span style="color:#0550AE;">string</span><span style="color:#24292F;">&gt; </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> </span><span style="color:#6E7781;">/* --snip-- */</span><span style="color:#24292F;"> ___</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CF222E;">const</span><span style="color:#24292F;"> </span><span style="color:#0550AE;">mapped</span><span style="color:#CF222E;">:</span><span style="color:#24292F;"> </span><span style="color:#953800;">Option</span><span style="color:#24292F;">&lt;</span><span style="color:#0550AE;">number</span><span style="color:#24292F;">&gt; </span><span style="color:#CF222E;">=</span><span style="color:#24292F;"> result.</span><span style="color:#8250DF;">match</span><span style="color:#24292F;">({</span></span>
<span class="line"><span style="color:#24292F;">  </span><span style="color:#8250DF;">Ok</span><span style="color:#24292F;">(</span><span style="color:#953800;">num</span><span style="color:#24292F;">) {</span></span>
<span class="line"><span style="color:#24292F;">    </span><span style="color:#CF222E;">return</span><span style="color:#24292F;"> Enum.</span><span style="color:#8250DF;">variant</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;Some&#39;</span><span style="color:#24292F;">, num)</span></span>
<span class="line"><span style="color:#24292F;">  },</span></span>
<span class="line"><span style="color:#24292F;">  </span><span style="color:#8250DF;">Err</span><span style="color:#24292F;">() {</span></span>
<span class="line"><span style="color:#24292F;">    </span><span style="color:#CF222E;">return</span><span style="color:#24292F;"> Enum.</span><span style="color:#8250DF;">variant</span><span style="color:#24292F;">(</span><span style="color:#0A3069;">&#39;None&#39;</span><span style="color:#24292F;">)</span></span>
<span class="line"><span style="color:#24292F;">  },</span></span>
<span class="line"><span style="color:#24292F;">})</span></span>
<span class="line"></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can use <code>match</code> method just for side-effects without returning anything from it.</p></div></li></ul><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-hidden="true">#</a></h2><p>Enums are just a part of SCALE. Let&#39;s dive into the core library.</p>`,20),p=[e];function t(c,r,i,y,F,d){return a(),n("div",null,p)}var g=s(o,[["render",t]]);export{h as __pageData,g as default};
